import $ from './jquery';
import 'select2/dist/js/select2.full';
import * as ArrayData from 'select2/src/js/select2/data/array';
import * as AjaxData from 'select2/src/js/select2/data/ajax';
import * as Utils from 'select2/src/js/select2/utils';
import * as InitSelection from 'select2/src/js/select2/compat/initSelection';
import layer from './layer';
import { getMessageLogger } from './internal/deprecation';
import globalize from './internal/globalize';

/**
 * Wraps a vanilla Select2 with ADG _style_, as an auiSelect2 method on jQuery objects.
 *
 * @since 5.2
 */

/**
 * We make a copy of the original select2 so that later we might re-specify $.fn.auiSelect2 as $.fn.select2. That
 * way, calling code will be able to call $thing.select2() as if they were calling the original library,
 * and ADG styling will just magically happen.
 */
const originalSelect2 = $.fn.select2;

// AUI-specific classes
const auiContainer = 'aui-select2-container';
const auiDropdown = 'aui-select2-drop aui-dropdown2';
const auiHasAvatar = 'aui-has-avatar';

// Other constants
const DROPDOWN_LAYER_KEY = 'aui.select2DropdownLayer';

const ajaxQuietMillisDeprecatedLogger = getMessageLogger('auiSelect2.ajax.quietMillis', {
    sinceVersion: '10.0.0',
    removeInVersion: '11.0.0',
    extraInfo: 'Use ajax.delay instead.',
});
const ajaxResultsDeprecatedLogger = getMessageLogger('auiSelect2.ajax.results', {
    sinceVersion: '10.0.0',
    removeInVersion: '11.0.0',
    extraInfo: 'Use ajax.processResults instead.',
});
const formatResultDeprecatedLogger = getMessageLogger('auiSelect2.formatResult', {
    sinceVersion: '10.0.0',
    removeInVersion: '11.0.0',
    extraInfo: 'Use templateResult instead.',
});
const formatSelectionDeprecatedLogger = getMessageLogger('auiSelect2.formatSelection', {
    sinceVersion: '10.0.0',
    removeInVersion: '11.0.0',
    extraInfo: 'Use templateSelection instead.',
});
const queryDeprecatedLogger = getMessageLogger('auiSelect2.query', {
    sinceVersion: '10.0.0',
    removeInVersion: '11.0.0',
    extraInfo: 'Use dataAdapter with `query` method instead.',
});
const initSelectionDeprecatedLogger = getMessageLogger('auiSelect2.initSelection', {
    sinceVersion: '10.0.0',
    removeInVersion: '11.0.0',
    extraInfo: 'Use dataAdapter with `current` method instead.',
});

$.fn.auiSelect2 = function (first) {
    /**
     * Adds AUI CSS classes to override default CSS.
     * @param {Object} options
     */
    function addAUICssOverrides(options) {
        const auiAvatarClass = options.hasAvatar ? ' ' + auiHasAvatar : '';
        options.containerCssClass =
            auiContainer +
            auiAvatarClass +
            (options.containerCssClass ? ' ' + options.containerCssClass : '');
        options.dropdownCssClass =
            auiDropdown +
            auiAvatarClass +
            (options.dropdownCssClass ? ' ' + options.dropdownCssClass : '');
    }

    /**
     * Handles custom error handlers for AJAX requests.
     * @param {Object} options
     */
    function handleAjaxError(options = {}) {
        if (options.ajax && options.ajax.params && options.ajax.params.error) {
            let customErrorHandlers = options.ajax.params.error;
            if (!Array.isArray(customErrorHandlers)) {
                customErrorHandlers = [customErrorHandlers];
            }
            let originalTransport = options.ajax.transport;
            if (!originalTransport) {
                const defaults = AjaxData.prototype._applyDefaults({});
                originalTransport = defaults.transport;
            }

            const newTransport = function (...args) {
                args[0].error = [args[0].error, ...customErrorHandlers];
                return originalTransport(...args);
            };

            options.ajax.transport = newTransport;
        }
    }

    /**
     * Migrate options to be compatibility with v3.
     * @param {Object} options
     */
    // eslint-disable-next-line complexity
    function migrateOptionsFromV3ToV4(options = {}) {
        // Default to true
        options.migrate = options.migrate === false ? false : true;

        if (!options.migrate) {
            return;
        }

        if (options.ajax) {
            if (options.ajax.quietMillis && !options.ajax.delay) {
                ajaxQuietMillisDeprecatedLogger();
                options.ajax.delay = options.ajax.quietMillis;
            }
            if (options.ajax.results && !options.ajax.processResults) {
                ajaxResultsDeprecatedLogger();
                options.ajax.processResults = function (data, params) {
                    const results = options.ajax.results.call(this, data, params.page || 1);
                    if (typeof results === 'object' && results.more) {
                        results.pagination = {
                            more: results.more,
                        };
                    }
                    return results;
                };
            }
        }

        if (options.formatResult && !options.templateResult) {
            formatResultDeprecatedLogger();
            options.templateResult = function (params, container) {
                const output = options.formatResult(params, container);
                // HTML strings must be wrapped in jQuery or Select2 escapes them
                if (/[&<>"'\/\\]/gi.test(output)) {
                    return $(output);
                }
                return output;
            };
        }

        if (options.formatSelection && !options.templateSelection) {
            formatSelectionDeprecatedLogger();
            options.templateSelection = function (params, container) {
                const output = options.formatSelection(params, container);
                // HTML strings must be wrapped in jQuery or Select2 escapes them
                if (/[&<>"'\/\\]/gi.test(output)) {
                    return $(output);
                }
                return output;
            };
        }

        // Select2.full has it's own migration for `query` option
        // however, due to a bug it does not work with `templateSelection`
        if (options.query && !options.dataAdapter) {
            queryDeprecatedLogger();
            function CustomData($element, options) {
                CustomData.__super__.constructor.call(this, $element, options);
            }

            Utils.Extend(CustomData, ArrayData);

            CustomData.prototype.query = function (params, callback) {
                params.term = params.term || '';
                params.callback = callback;
                CustomData.prototype._query(params);
            };

            CustomData.prototype._query = options.query;

            options.dataAdapter = CustomData;
            // Remove query option so it will not conflict with existing migration
            delete options.query;
        }

        if (options.initSelection && options.dataAdapter) {
            initSelectionDeprecatedLogger();
            options.dataAdapter = Utils.Decorate(options.dataAdapter, InitSelection);
        }
    }

    /**
     * Initializes event handlers.
     * @param {Node} select2Instance
     * @param {Object} options
     */
    function initEventHandlers(select2Instance, options = {}) {
        const searchLabel = options.searchLabel;

        select2Instance.on('select2:open', function () {
            const $selectInput = $(this);
            const $selectDropdown = $selectInput.data('select2').$dropdown;

            let dropdownLayer = $selectInput.data(DROPDOWN_LAYER_KEY);

            if (!dropdownLayer) {
                dropdownLayer = layer();
                $selectInput.data(DROPDOWN_LAYER_KEY, dropdownLayer);
            }

            dropdownLayer.show(); // add layer to layer manager to get top z-index

            $selectDropdown.css('z-index', dropdownLayer.$el.css('z-index'));

            if (options.multiple || $selectInput.attr('multiple')) {
                // This is a multi-select, exiting
                return;
            }

            // Create assistive label for dropdown search input
            if (searchLabel) {
                $selectDropdown
                    .find('.select2-search.select2-search--dropdown')
                    .prepend(`<span class="assistive">${searchLabel}</span>`);
            }
        });

        select2Instance.on('select2:close', function () {
            const $selectInput = $(this);
            const dropdownLayer = $selectInput.data(DROPDOWN_LAYER_KEY);

            if (dropdownLayer) {
                dropdownLayer.hide();
            } else {
                AJS.warn(
                    'Warning! AUI: `select2:close` event handler could not discover the layer linked with the Select2 dropdown.',
                    'This may be happening when there are many instances of Select2 created on the same DOM element.',
                    'Consider checking your code as this can negatively affect performance.'
                );
            }
        });
    }

    let updatedArgs = arguments;

    if ($.isPlainObject(first)) {
        const options = $.extend({}, first);

        updatedArgs = Array.prototype.slice.call(arguments, 1);
        updatedArgs.unshift(options);
    } else if (!arguments.length) {
        updatedArgs = [{}];
    }

    if (this.hasClass('select2-hidden-accessible')) {
        // Initialised already, pass through
        return originalSelect2.apply(this, updatedArgs);
    }

    const options = updatedArgs[0];

    addAUICssOverrides(options);
    handleAjaxError(options);
    migrateOptionsFromV3ToV4(options);
    initEventHandlers(this, options);

    return originalSelect2.apply(this, updatedArgs);
};

// Expose the original select2 methods to create custom Data Adapters
globalize('auiSelect2', { Utils, ArrayData, AjaxData });
